<?php
namespace Tests\Feature\Hr;use App\Models\HrLicense;use App\Models\LegalEntity;use App\Models\User;use App\Modules\Hr\Core\Services\TenantContext;use Illuminate\Support\Facades\DB;use Tests\TestCase;
class LifecyclePagesTest extends TestCase{use RefreshHrDatabase;public function test_lifecycle_page_renders():void{(new \Database\Seeders\Hr\HrPermissionSeeder)->run();$role=DB::table('roles')->where('slug','hr_admin')->value('id');$user=User::factory()->create(['role_id'=>$role]);$this->actingAs($user);$tenant=LegalEntity::create(['user_id'=>$user->id,'name'=>'Yaşam','tax_number'=>'8282828282','is_active'=>true]);app(TenantContext::class)->set($tenant);HrLicense::create(['legal_entity_id'=>$tenant->id,'module_key'=>'personel','is_active'=>true]);$this->get(route('hr.lifecycle'))->assertOk()->assertSee('İşe Giriş');}}
